async function run() {
  const target = await getTargetChannel();
  const now = new Date();
  const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

  const result = await summarizeChannel({
    channelId: target.channelId,
    fromIso: yesterday.toISOString(),
    toIso: now.toISOString(),
  });

  return result;
}

run();

